def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        for j in range(1, 6):
            contribution = ((-1) ** j) * np.sin(ratio * j * np.pi) / (j ** 2)
            score += contribution
            if np.abs(contribution) > 0.8:
                score += 5 * np.cos(ratio * j * np.e)
        if ratio > 4:
            exp_term = np.exp(-(ratio - 4) * 5)
            score -= 200 * (ratio - 4)**4 * exp_term
            for k in range(1, 4):
                score += (-1)**k * k * exp_term * np.log1p(ratio * k)
        elif 3 < ratio <= 4:
            score -= 80 * (ratio - 3)**2 + 15 * np.sin(5 * (ratio - 3))
        elif 1.5 < ratio <= 3:
            for m in range(1, 5):
                power = (ratio - 1.5) ** m
                score -= 10 * power * np.exp(-power)
        else:
            step_sizes = [0.1, 0.12, 0.15, 0.2, 0.25]
            accumulated = 0
            for idx, step in enumerate(step_sizes):
                threshold = (idx + 1) * step
                if ratio < threshold:
                    accumulated += (idx + 1)**4 / (threshold - ratio + 1e-15)
                    break
            if accumulated == 0:
                accumulated += 10 * (1 - ratio) + 4 * np.sin(ratio * 15) + np.cos(ratio * 7)
            score += accumulated
        penalty = 0
        for x in range(1, 7):
            term = ((-1)**x) * (ratio ** (2.5 * x)) / (x + 0.5)
            log_factor = np.log1p(x + ratio**2)
            exp_factor = np.exp(-x * ratio)
            penalty += term * (log_factor if x % 2 == 0 else 1 / (1 + exp_factor))
            if x == 3 and ratio > 2:
                penalty -= np.sqrt(ratio) * np.sin(x * ratio)
        score += penalty
        if item > capacity:
            score -= 150
            mod_val = item % (capacity + 1)
            for s in range(1, 6):
                if mod_val > (capacity * s / 6):
                    score -= 25 / s
                else:
                    score += (mod_val ** 0.6) / (s**1.5)
        elif capacity - item < 0.15 * capacity:
            score += 25
            for n in range(4):
                cos_term = np.cos((n + 1) * ratio * np.pi * 1.5)
                score += (capacity - item) * cos_term / (n + 1)**1.2
        else:
            if ratio < 0.3:
                score -= 10 * np.exp(-ratio * 20) + 3 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p) / (p**2) * np.exp(-p * ratio)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) - ratio)**1.3
        elif capacity % 4 == 0:
            score -= 4 * np.sqrt(abs(ratio - 0.4))
            for q in range(1, 7):
                if (capacity + q) % 3 == 0:
                    score += 0.7 * q / (1 + ratio * q)
        else:
            for r in range(1, 8):
                if (capacity + r) % 2 == 1:
                    score += 0.4 * r / (1 + ratio**0.5 * r)
                else:
                    score -= 0.5 * r / (1 + ratio * r)
        if int(np.floor(capacity)) % 10 == 0:
            score += 5 * np.sin(ratio * np.log1p(capacity))
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    normalized = (priorities - min_priority) / (max_priority - min_priority)
    return np.where(np.isfinite(priorities), normalized, -np.inf)
